ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?city a :City .
    ?hotel a :Hotels .
    ?hotel p:hasCity ?city .
    ?swimmingpool a :SwimmingPool .
    ?swimmingpool p:hasHotel ?hotel .
    ?swimmingpool p:Size ?size .
    ?city p:name ?name_f .
    FILTER(STR(?name_f) = "Miami")
    BIND(?size AS ?o0)
  }
  UNION
  {
    ?city a :City .
    ?hotel a :Hotels .
    ?hotel p:hasCity ?city .
    ?hottub a :HotTub .
    ?hottub p:hasHotel ?hotel .
    ?hottub p:Capacity ?capacity .
    ?city p:name ?name_f .
    FILTER(STR(?name_f) = "Miami")
    BIND(?capacity AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?city a :City .
    ?hotel a :Hotels .
    ?hotel p:hasCity ?city .
    ?swimmingpool a :SwimmingPool .
    ?swimmingpool p:hasHotel ?hotel .
    ?swimmingpool p:Size ?size .
    BIND(?size AS ?o0)
  }
  UNION
  {
    ?city a :City .
    ?hotel a :Hotels .
    ?hotel p:hasCity ?city .
    ?hottub a :HotTub .
    ?hottub p:hasHotel ?hotel .
    ?hottub p:Capacity ?capacity .
    ?city p:name ?name_f .
    FILTER(STR(?name_f) = "Miami")
    BIND(?capacity AS ?o0)
  }
} }
}
